import{_ as e,C as p,o as t,c as l,ag as s,E as r}from"./chunks/framework.CAXxHpAX.js";const i="/images/chapter-00.svg",P=JSON.parse('{"title":"0. 核心定位","description":"说明本书为什么以 PostgreSQL 为入口，如何把数据库学习连接到大数据与 AI 数据基础设施。","frontmatter":{"title":"0. 核心定位","description":"说明本书为什么以 PostgreSQL 为入口，如何把数据库学习连接到大数据与 AI 数据基础设施。","prev":false,"next":{"text":"1. 数据库基础：用 PostgreSQL 建立数据系统直觉","link":"/chapters/01-postgresql-foundations"}},"headers":[],"relativePath":"chapters/00-positioning.md","filePath":"chapters/00-positioning.md"}'),o={name:"chapters/00-positioning.md"};function d(c,a,h,b,u,g){const n=p("Mermaid");return t(),l("div",null,[a[0]||(a[0]=s('<h1 id="_0-核心定位" tabindex="-1">0. 核心定位 <a class="header-anchor" href="#_0-核心定位" aria-label="Permalink to &quot;0. 核心定位&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>说明本书为什么以 PostgreSQL 为入口，如何把数据库学习连接到大数据与 AI 数据基础设施。</p></div><p><img src="'+i+'" alt="核心定位"></p><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',5)),r(n,{code:"flowchart%20LR%0A%20%20A%5B%22%E4%BC%9A%E6%9F%A5%E6%95%B0%E6%8D%AE%22%5D%20--%3E%20B%5B%22PostgreSQL%20%E7%9B%B4%E8%A7%89%22%5D%0A%20%20B%20--%3E%20C%5B%22SQL%20%E5%88%86%E6%9E%90%22%5D%0A%20%20C%20--%3E%20D%5B%22%E6%95%B0%E4%BB%93%E4%B8%8E%E6%95%B0%E6%8D%AE%E9%93%BE%E8%B7%AF%22%5D%0A%20%20D%20--%3E%20E%5B%22%E6%89%B9%E5%A4%84%E7%90%86%20%2F%20%E5%AE%9E%E6%97%B6%20%2F%20OLAP%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%B9%96%E4%BB%93%22%5D%0A%20%20F%20--%3E%20G%5B%22%E5%90%91%E9%87%8F%20%2F%20%E5%9B%BE%22%5D%0A%20%20G%20--%3E%20H%5B%22%E6%99%BA%E8%83%BD%E6%95%B0%E6%8D%AE%E7%B3%BB%E7%BB%9F%22%5D%0A"}),a[1]||(a[1]=s(`<h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>这本书不是 PostgreSQL 使用手册，也不是 SQL 语法大全，更不是大数据工具名录。</p><p>它要解决的问题是：一个已经会查一些数据的人，如何建立完整的数据系统理解，最终能看懂并参与构建大数据与 AI 数据基础设施。</p><p>如果学习路线从工具开始，读者很容易陷入清单式学习：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>今天学 PostgreSQL</span></span>
<span class="line"><span>明天学 Spark</span></span>
<span class="line"><span>后天学 Flink</span></span>
<span class="line"><span>再学 ClickHouse、Iceberg、Milvus、Neo4j</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这种学习方式的问题是：工具越学越多，系统关系反而越来越模糊。</p><p>更稳定的路线，是从 PostgreSQL 出发，先理解一个业务数据库如何组织数据、约束数据、查询数据和保持一致；再看当数据量、分析需求、实时性和 AI 应用要求持续增长时，系统为什么会演化出 OLAP、数仓、ETL / CDC、批处理、实时计算、湖仓、向量数据库、图数据库和数据治理。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>本书的核心判断是：数据库学习不应该从工具清单开始，而应该从数据系统的演化路径开始。PostgreSQL 是入口，因为它能让读者先理解数据组织、约束、事务、查询和单机边界，再自然进入大数据和 AI 数据基础设施。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="一、postgresql-的角色" tabindex="-1">一、PostgreSQL 的角色 <a class="header-anchor" href="#一、postgresql-的角色" aria-label="Permalink to &quot;一、PostgreSQL 的角色&quot;">​</a></h3><p>PostgreSQL 在本书里有四个角色。</p><p>第一，它是数据库直觉训练场。</p><p>你可以在 PostgreSQL 里看到一个数据系统最基础的问题：数据放在哪里，如何命名，如何建立关系，如何避免错误写入，如何在多步修改中保持一致，如何为查询选择访问路径。</p><p>第二，它是 OLTP 到 OLAP 的桥梁。</p><p>PostgreSQL 适合支撑业务系统，但业务增长后，分析查询会逐渐和在线交易产生资源冲突。理解这个冲突，才能真正理解为什么 OLTP 和 OLAP 会分化。</p><p>第三，它是大数据链路中常见的数据源。</p><p>很多数仓、实时数仓、湖仓和指标平台，最早的数据都来自 PostgreSQL 或类似业务库。订单、用户、支付、权限、状态变化，都从业务库进入 ETL、CDC、Kafka、Flink、Spark、ClickHouse 或 Iceberg。</p><p>第四，它是 AI 数据系统的重要基础组件。</p><p>AI 应用不是只靠模型运行。RAG 需要文档元数据、权限、Chunk、Embedding 版本、召回日志和评测记录；GraphRAG 需要实体、关系、图谱版本和路径查询记录。PostgreSQL 经常承担这些结构化元数据和控制数据。</p><h3 id="二、总学习路线" tabindex="-1">二、总学习路线 <a class="header-anchor" href="#二、总学习路线" aria-label="Permalink to &quot;二、总学习路线&quot;">​</a></h3><p>本书的路线不是平铺所有概念，而是一条演化路径：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL 基础</span></span>
<span class="line"><span>  -&gt; SQL 分析能力</span></span>
<span class="line"><span>  -&gt; 大表与查询优化</span></span>
<span class="line"><span>  -&gt; OLTP vs OLAP</span></span>
<span class="line"><span>  -&gt; 数仓建模</span></span>
<span class="line"><span>  -&gt; ETL / ELT / CDC</span></span>
<span class="line"><span>  -&gt; 批处理</span></span>
<span class="line"><span>  -&gt; 实时数据处理</span></span>
<span class="line"><span>  -&gt; OLAP 数据库</span></span>
<span class="line"><span>  -&gt; 向量数据库</span></span>
<span class="line"><span>  -&gt; 图数据库</span></span>
<span class="line"><span>  -&gt; 数据湖 / 湖仓</span></span>
<span class="line"><span>  -&gt; 数据治理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>这条路线的关键不是“每个工具都懂一点”，而是理解每个系统为什么出现。</p><p>SQL 为什么是大数据系统的共同语言？</p><p>因为无论底层是 PostgreSQL、Hive、Spark SQL、Trino、ClickHouse 还是 Doris，业务分析最终都需要把问题表达成筛选、关联、聚合、排序、窗口计算和指标口径。</p><p>OLAP 为什么从 OLTP 中分化出来？</p><p>因为高频小事务和大范围分析扫描对存储、执行、延迟和一致性的要求不同。</p><p>ETL / CDC 为什么重要？</p><p>因为数据不会天然出现在数仓里，必须从业务系统被抽取、同步、清洗、转换和装载。</p><p>湖仓为什么出现？</p><p>因为数据湖提供低成本开放存储，数仓提供建模和治理能力，现代平台希望同时获得开放性、事务性、可演化表结构和多引擎查询。</p><p>向量数据库和图数据库为什么进入数据基础设施？</p><p>因为 AI 应用不只查询结构化表，还需要语义相似性检索、实体关系网络、多跳推理和可追溯上下文。</p><h3 id="深度展开-全书定位如何落到真实系统" tabindex="-1">深度展开：全书定位如何落到真实系统 <a class="header-anchor" href="#深度展开-全书定位如何落到真实系统" aria-label="Permalink to &quot;深度展开：全书定位如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>很多数据库学习路径把知识拆成孤立工具，导致读者会写 SQL、听过大数据组件，却无法解释系统为什么从业务库演化到数仓、湖仓、向量、图和治理。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是读者已有的零散经验：查过表、写过 SQL、听过 PostgreSQL、Spark、Flink、ClickHouse、Milvus 或 Neo4j，但缺少把它们放进同一条数据系统演化链路的框架。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是先用 PostgreSQL 建立数据组织和一致性直觉，再用 SQL 建立分析表达能力，随后沿着大表边界、OLTP / OLAP 分化、数仓建模、数据链路、批流计算、OLAP、湖仓、向量、图和治理逐步展开。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>在真实平台里，这条路径对应一条端到端数据链路：业务库记录事实，分析系统重构事实，计算系统加工事实，检索和图系统扩展事实，治理系统保证事实可信。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>本书不是某个数据库的参数手册，也不是大数据工具百科。它不会追求覆盖所有产品细节，而是训练读者理解问题、机制、边界和迁移关系。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>只会背工具名但说不清上下游</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>能写 SQL 但解释不了指标口径</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>能跑 RAG Demo 但没有数据治理</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>能画架构图但说不清每层责任</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>在正式阅读前，画出自己理解的数据链路：业务库、SQL、数仓、同步、批处理、实时、OLAP、湖仓、向量、图、治理分别在哪里，哪些还说不清。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>第 0 章是全书的定位层。它不展开某个单点技术，而是规定全书的叙事方式：从 PostgreSQL 出发，沿着 SQL、OLTP/OLAP、数仓、链路、批流、湖仓、向量、图和治理逐步演化。</p><p>后续每一章都要回到这个问题：当前机制解决了上一阶段留下的什么压力，又为什么会引出下一阶段系统。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><h3 id="三、最小闭环" tabindex="-1">三、最小闭环 <a class="header-anchor" href="#三、最小闭环" aria-label="Permalink to &quot;三、最小闭环&quot;">​</a></h3><p>如果把整条路线压缩成一个最小闭环，它是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL 业务数据</span></span>
<span class="line"><span>  -&gt; SQL 分析</span></span>
<span class="line"><span>  -&gt; 数仓建模</span></span>
<span class="line"><span>  -&gt; ETL / CDC</span></span>
<span class="line"><span>  -&gt; ClickHouse / Spark / Flink</span></span>
<span class="line"><span>  -&gt; 向量检索 / 图关系分析</span></span>
<span class="line"><span>  -&gt; 指标、BI、RAG、GraphRAG 和数据应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个闭环里，PostgreSQL 不是被淘汰，而是继续承担可靠业务事实和元数据管理。</p><p>SQL 不是被替换，而是成为跨系统分析语言。</p><p>数仓不是简单复制业务库，而是重构分析语义。</p><p>ETL / CDC 不是搬运文件，而是构建可信数据链路。</p><p>批处理、实时计算和 OLAP 数据库不是堆工具，而是分别处理历史计算、事件流和高性能分析。</p><p>向量数据库和图数据库不是传统数据库替代品，而是为语义检索和关系网络提供新的查询能力。</p><p>数据治理不是最后的装饰，而是让所有数据长期可信、可追溯、可复用、可控制的基础。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：这本书是 PostgreSQL 手册。</strong></p><p>PostgreSQL 是入口，不是全部。本书关心的是如何从 PostgreSQL 建立数据系统直觉，并迁移到大数据和 AI 数据基础设施。</p><p><strong>误区二：大数据学习就是工具越多越好。</strong></p><p>工具清单不能形成系统理解。每个工具都要放回它解决的问题、边界和上下游关系中。</p><p><strong>误区三：AI 数据系统可以跳过传统数据基础。</strong></p><p>RAG、GraphRAG 和智能应用仍然依赖元数据、权限、质量、血缘、评测和治理。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>阅读本书前，先画一张自己的数据系统路线图，至少回答：</p><ul><li>当前你会哪些 SQL 或数据库操作？</li><li>你是否能解释 PostgreSQL、数仓、OLAP、湖仓、向量库和图数据库的关系？</li><li>你最想解决的是业务报表、实时监控、RAG、GraphRAG，还是数据治理？</li><li>你当前最薄弱的是 SQL、建模、链路、选型还是治理？</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><h3 id="四、学习后的能力变化" tabindex="-1">四、学习后的能力变化 <a class="header-anchor" href="#四、学习后的能力变化" aria-label="Permalink to &quot;四、学习后的能力变化&quot;">​</a></h3><p>本书希望完成的迁移是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>会查数据</span></span>
<span class="line"><span>  -&gt; 能理解业务数据如何建模</span></span>
<span class="line"><span>  -&gt; 能写分析 SQL 和指标 SQL</span></span>
<span class="line"><span>  -&gt; 能判断 PostgreSQL 的查询边界</span></span>
<span class="line"><span>  -&gt; 能区分 OLTP 与 OLAP</span></span>
<span class="line"><span>  -&gt; 能设计数仓分层和数据链路</span></span>
<span class="line"><span>  -&gt; 能理解批处理、实时计算和湖仓</span></span>
<span class="line"><span>  -&gt; 能把向量、图和治理纳入 AI 数据系统</span></span>
<span class="line"><span>  -&gt; 能构建智能数据系统的基础架构</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这不是一条只服务数据库管理员的路线，也不是一条只服务数据工程师的路线。</p><p>它服务的是任何想真正理解数据基础设施的人：后端工程师、数据工程师、AI 应用工程师、数据产品经理、技术负责人，都可以从这条路径里获得系统判断。</p><h3 id="五、如何阅读本书" tabindex="-1">五、如何阅读本书 <a class="header-anchor" href="#五、如何阅读本书" aria-label="Permalink to &quot;五、如何阅读本书&quot;">​</a></h3><p>阅读时不要把每个概念当作单独术语背诵。</p><p>每遇到一个概念，都问五个问题：</p><ol><li>它解决什么问题？</li><li>它不解决什么问题？</li><li>它为什么出现？</li><li>它和前后系统是什么关系？</li><li>它在真实数据平台中如何落地？</li></ol><p>只要保持这个问题框架，PostgreSQL、SQL、数仓、Spark、Flink、ClickHouse、Iceberg、Milvus、Neo4j 和数据治理，就不会再是散落的工具名，而会连成一条清晰的数据系统演化路径。</p>`,93))])}const L=e(o,[["render",d]]);export{P as __pageData,L as default};
